INSERT INTO `convocatorias` (`IDCONVOCATORIA`, `area`, `puesto`, `sueldo`, `tituloProfesional`, `expPublicaMin`, `expPublicaMax`, `experienciaTotal`, `fechaInicio`, `fechaFin`, `estado`, `publicada`, `numeroCAS`, `requisitosAcademicos`, `habilidadesTecnicas`, `fechaCreacion`, `fechaActualizacion`) VALUES
(1, 'Administración - Informática', 'Analista de datos', '4000.00', 'Sí', '1 año', '2 años', '2 años', '2025-11-01', '2026-09-01', 'Inactivo', 1, 'CAS N° 12', 'Título profesional en Ingeniería de Sistemas o afines', 'Análisis y gestión de datos\n\nDominio de Excel avanzado (tablas dinámicas, fórmulas, macros, Power Query).\n\nManejo de bases de datos relacionales (MySQL, SQL Server, PostgreSQL).\n\nConocimientos en lenguajes de consulta SQL para extracción y transformación de datos.\n\nExperiencia en ETL (Extract, Transform, Load) y limpieza de datos.\n\n2. Programación y análisis estadístico\n\nUso de Python (pandas, NumPy, matplotlib, seaborn) o R para análisis de datos.\n\nConocimientos básicos de estadística descriptiva e inferencial.\n\nModelos predictivos y machine learning básico (Scikit-learn, TensorFlow, etc.).\n\n3. Visualización y presentación de datos\n\nDominio de herramientas de Business Intelligence (BI) como Power BI, Tableau o Google Data Studio.\n\nCreación de dashboards interactivos e informes visuales.\n\nInterpretación y comunicación de resultados a públicos no técnicos.\n\n4. Conocimientos en almacenamiento y manejo de información\n\nUso de Microsoft Access o sistemas similares.\n\nConocimientos en Big Data (opcional): Hadoop, Spark, Azure Data Lake, etc.\n\nGestión de información conforme a políticas de seguridad y confidencialidad de datos.', '2025-11-02 00:17:33', '2025-11-08 15:25:46'),
(2, 'Administración - Tesorería', 'Contabilidad', '1500.00', 'No', '2 meses', '1 año', '1 año', '2025-11-01', '2026-02-01', 'Inactivo', 1, 'CAS N° 13', 'Administrador de Contabilidad', '1. Gestión Financiera y Tesorería\n\nAdministración eficiente de flujos de caja, ingresos y egresos.\n\nElaboración y control de presupuestos operativos y financieros.\n\nManejo de conciliaciones bancarias, arqueos de caja y control de fondos fijos.\n\nCoordinación de pagos a proveedores y cobranzas a clientes.\n\nSeguimiento de líneas de crédito, préstamos y obligaciones financieras.\n\nOptimización de la liquidez y gestión del riesgo financiero.\n\n2. Contabilidad General\n\nRegistro contable de operaciones financieras y administrativas.\n\nPreparación de estados financieros: Balance General, Estado de Resultados, Flujo de Efectivo.\n\nManejo de plan contable general empresarial (PCGE) y normas contables vigentes (NIIF / IFRS).\n\nControl y conciliación de cuentas por cobrar, pagar y activos fijos.\n\nElaboración de asientos de cierre, provisiones y ajustes contables.', '2025-11-02 02:32:40', '2025-11-08 15:25:43'),
(3, 'Administración - Informática', 'servidor', '4000.00', 'Sí', '1 años', '10 años', '2 años', '2025-01-08', '2025-11-08', 'Inactivo', 1, 'CAS N° 15', 'ing sistema', 'Sistemas Operativos de Servidor\n\nWindows Server (Active Directory, IIS, PowerShell, etc.)\n\nLinux/Unix (Ubuntu Server, CentOS, Red Hat, Debian)\n\nAdministración de servicios: SSH, DNS, DHCP, NFS, Samba, etc.\n\nVirtualización\n\nVMware vSphere / ESXi\n\nMicrosoft Hyper-V\n\nProxmox, KVM, Xen\n\nRedes\n\nProtocolos: TCP/IP, HTTP/HTTPS, DNS, FTP, SMTP\n\nConfiguración de firewalls, routers y switches\n\nVPNs, VLANs, NAT y balanceo de carga\n\nAlmacenamiento\n\nRAID, SAN, NAS\n\nSistemas de archivos (NTFS, EXT4, XFS, ZFS)\n\nCopias de seguridad (backups) y recuperación de desastres\n\nSeguridad\n\nEndurecimiento del sistema (hardening)\n\nControl de acceso y permisos\n\nAuditorías, logs, IDS/IPS\n\nCertificados SSL/TLS\n\nAutomatización y Scripting\n\nBash, PowerShell, Python\n\nHerramientas: Ansible, Puppet, Chef, SaltStack\n\nCron jobs y tareas automatizadas\n\nServidores Web y Aplicaciones\n\nApache, Nginx, IIS\n\nServidores de bases de datos: MySQL, PostgreSQL, SQL Server\n\nServidores de correo: Postfix, Exchange\n\nCloud Computing\n\nAWS, Azure, Google Cloud Platform\n\nInfraestructura como servicio (IaaS)\n\nContenedores y orquestación: Docker, Kubernetes\n\nMonitoreo y Rendimiento\n\nNagios, Zabbix, Prometheus, Grafana\n\nLogs centralizados (ELK Stack, Graylog)\n\nControl de Versiones y DevOps\n\nGit / GitHub / GitLab\n\nCI/CD (Jenkins, GitHub Actions, GitLab CI)', '2025-11-08 09:31:09', '2025-11-08 15:25:40');

