--
-- Estructura de tabla para la tabla `reportes_ia`
--

CREATE TABLE `reportes_ia` (
  `IDREPORTE` int(11) NOT NULL,
  `IDUSUARIO` int(11) NOT NULL,
  `IDCONVOCATORIA` int(11) NOT NULL,
  `nombre_completo` varchar(255) DEFAULT NULL,
  `email` varchar(255) DEFAULT NULL,
  `puesto_postulado` varchar(255) DEFAULT NULL,
  `score` int(11) DEFAULT 0,
  `calificacion` decimal(3,1) DEFAULT 0.0,
  `estado_evaluacion` enum('approved','rejected','pending') DEFAULT 'pending',
  `apto` tinyint(1) DEFAULT 0,
  `analisis` longtext DEFAULT NULL,
  `razones` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_bin DEFAULT NULL CHECK (json_valid(`razones`)),
  `motivo_rechazo` text DEFAULT NULL,
  `experiencia_relevante` text DEFAULT NULL,
  `habilidades_clave` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_bin DEFAULT NULL CHECK (json_valid(`habilidades_clave`)),
  `convocatoria_usada` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_bin DEFAULT NULL CHECK (json_valid(`convocatoria_usada`)),
  `totalAnexos` int(11) DEFAULT 0,
  `declaraciones` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_bin DEFAULT NULL CHECK (json_valid(`declaraciones`)),
  `fechaCreacion` timestamp NOT NULL DEFAULT current_timestamp(),
  `fechaActualizacion` timestamp NOT NULL DEFAULT current_timestamp() ON UPDATE current_timestamp(),
  `reglasAplicadas` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_bin DEFAULT NULL CHECK (json_valid(`reglasAplicadas`)),
  `bonosAplicados` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_bin DEFAULT NULL CHECK (json_valid(`bonosAplicados`))
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

--
-- Volcado de datos para la tabla `reportes_ia`
--

INSERT INTO `reportes_ia` (`IDREPORTE`, `IDUSUARIO`, `IDCONVOCATORIA`, `nombre_completo`, `email`, `puesto_postulado`, `score`, `calificacion`, `estado_evaluacion`, `apto`, `analisis`, `razones`, `motivo_rechazo`, `experiencia_relevante`, `habilidades_clave`, `convocatoria_usada`, `totalAnexos`, `declaraciones`, `fechaCreacion`, `fechaActualizacion`, `reglasAplicadas`, `bonosAplicados`) VALUES
(1, 22, 1, 'Franklin Edin', 'franramitined@gmail.com', 'Analista de datos', 42, 4.2, 'rejected', 0, '# Análisis Exhaustivo de la Postulación del Candidato\n\n═══════════════════════════════════════════════════════════════\n0️⃣ REGLAS Y CRITERIOS APLICADOS\n═══════════════════════════════════════════════════════════════\n\n**REGLAS DE EVALUACIÓN:**\n- **Experiencia Pública Mínima:** 1 año\n- **Experiencia Pública Máxima:** 2 años\n\nEstas son las reglas que se aplicarán para evaluar el cumplimiento de requisitos.\n\n═══════════════════════════════════════════════════════════════\n1️⃣ EVALUACIÓN DE REQUISITOS DE LA CONVOCATORIA\n═══════════════════════════════════════════════════════════════\n\n**REQUISITOS CUMPLIDOS:**\n- **Experiencia Pública:** El postulante presenta experiencia laboral en el sector público, específicamente en la Municipalidad Provincial de Talara y UGEL Talara, cumpliendo con el requisito de 1 a 2 años.\n  - **Evidencia documental:** Referencias laborales que indican cargos desempeñados.\n  - **Detalles de los documentos/anexos:** Anexo 01 - Anexo_15.pdf.\n\n**REQUISITOS FALTANTES O INCOMPLETOS:**\n- **Formación Académica:** No se presenta un título profesional específico. La formación académica está marcada como \"N/A\".\n- **Especializaciones:** No se presentan especializaciones relevantes.\n- **Habilidades:** No se especifican habilidades requeridas en la convocatoria, lo que limita la evaluación.\n\n**DOCUMENTOS ADICIONALES PRESENTADOS:**\n- No se presentan documentos adicionales que fortalezcan la postulación.\n\n═══════════════════════════════════════════════════════════════\n2️⃣ ANÁLISIS DETALLADO DE EXPERIENCIA LABORAL\n═══════════════════════════════════════════════════════════════\n\n**EXPERIENCIA PRESENTADA:**\n- **Resumen de la experiencia laboral:**\n  - Asistente Administrativo en la Municipalidad Provincial de Talara.\n  - Analista de Sistemas en UGEL Talara.\n- **Años totales de experiencia:** 1 año (asumiendo que cada cargo ha sido desempeñado por un año).\n- **Años específicos de experiencia en el SECTOR PÚBLICO:** 1 año.\n\n**COMPARACIÓN CON REQUISITOS:**\n- **Experiencia requerida:** 1 a 2 años.\n- **Experiencia presentada:** 1 año.\n- **Cumplimiento:** SÍ CUMPLE.\n- **Diferencia:** 0 años faltantes.\n\n**VERIFICACIÓN ESPECÍFICA:**\n- Se verifica que el postulante tiene experiencia pública, cumpliendo con el requisito.\n\n**FORTALEZAS Y DEBILIDADES:**\n- **Fortalezas:** Experiencia en el sector público, lo que es relevante para el puesto.\n- **Debilidades:** Falta de información sobre la duración exacta de la experiencia laboral y la naturaleza de las tareas realizadas.\n\n═══════════════════════════════════════════════════════════════\n3️⃣ EVALUACIÓN ACADÉMICA Y FORMACIÓN\n═══════════════════════════════════════════════════════════════\n\n**TÍTULO PROFESIONAL REQUERIDO:**\n- **Título requerido:** \"No especificado\".\n- **Título presentado:** N/A.\n- **Cumplimiento:** NO CUMPLE.\n- **Justificación:** No se presenta un título profesional.\n\n**FORMACIÓN ACADÉMICA:**\n- **Títulos universitarios presentados:** No se especifica un título universitario.\n- **Nivel académico más alto alcanzado:** N/A.\n- **Instituciones donde estudió:** Universidad Nacional de Piura (sin título especificado).\n\n**ESPECIALIZACIONES Y ESTUDIOS ADICIONALES:**\n- No se presentan especializaciones o cursos relevantes.\n\n**COLEGIO PROFESIONAL:**\n- No se menciona pertenencia a un colegio profesional.\n\n═══════════════════════════════════════════════════════════════\n4️⃣ EVALUACIÓN DE HABILIDADES Y COMPETENCIAS\n═══════════════════════════════════════════════════════════════\n\n**IDIOMAS:**\n- **Idiomas dominados:** Avanzado (N/A) y Básico (N/A).\n- **Relevancia para el puesto:** No se especifica si el dominio de idiomas es relevante para el puesto.\n\n**CONOCIMIENTOS DE OFIMÁTICA:**\n- **Programas conocidos:** Ofimática (Avanzado).\n- **Relevancia para el puesto:** Conocimientos de ofimática son relevantes para un puesto de analista de datos.\n\n**HABILIDADES REQUERIDAS:**\n- No se especifican habilidades requeridas en la convocatoria, lo que limita la evaluación.\n\n═══════════════════════════════════════════════════════════════\n5️⃣ VERIFICACIÓN DE DECLARACIONES JURADAS\n═══════════════════════════════════════════════════════════════\n\n**DECLARACIONES MARCADAS:**\n- Todas las declaraciones juradas están marcadas como completas.\n- **Estado:** COMPLETO.\n\n**DECLARACIONES FALTANTES (CRÍTICO):**\n- No hay declaraciones faltantes.\n\n**ANÁLISIS DE COMPLETITUD:**\n- **Porcentaje de declaraciones completadas:** 100%.\n- **Evaluación de riesgo legal:** Bajo riesgo, ya que todas las declaraciones están completas.\n\n═══════════════════════════════════════════════════════════════\n6️⃣ BONIFICACIONES APLICABLES\n═══════════════════════════════════════════════════════════════\n\n**BONIFICACIONES IDENTIFICADAS:**\n- No se identifican bonificaciones aplicables.\n\n**PUNTOS ADICIONALES:**\n- No se presentan bonificaciones que sumen puntos adicionales.\n\n═══════════════════════════════════════════════════════════════\n7️⃣ OBSERVACIONES Y CALIDAD DOCUMENTAL\n═══════════════════════════════════════════════════════════════\n\n**CALIDAD DE LA DOCUMENTACIÓN:**\n- **Completitud:** Documentación incompleta en términos de formación académica.\n- **Claridad y legibilidad:** Documentos claros, pero falta información clave.\n- **Organización de la información:** Bien organizada, pero con información limitada.\n\n**ASPECTOS DESTACABLES:**\n- Experiencia en el sector público.\n- Cumplimiento de las declaraciones juradas.\n\n**ASPECTOS PREOCUPANTES:**\n- Falta de un título profesional.\n- Información incompleta sobre experiencia laboral.\n\n═══════════════════════════════════════════════════════════════\n8️⃣ RECOMENDACIÓN FINAL Y EVALUACIÓN\n═══════════════════════════════════════════════════════════════\n\n**NIVEL DE CUMPLIMIENTO:** PARCIAL\n\n**SCORE PROPUESTO (0-100):** 55\n- **Cálculo:** \n  - Requisitos cumplidos (40%): 20\n  - Experiencia (25%): 15\n  - Formación (20%): 5\n  - Habilidades (10%): 5\n  - Declaraciones (5%): 5\n\n**JUSTIFICACIÓN DE LA DECISIÓN:**\n- El postulante cumple con la experiencia mínima requerida, pero no presenta un título profesional ni especializaciones relevantes, lo que afecta su puntuación en formación.\n\n**VEREDICTO FINAL:**\n- **APTO:** NO\n- **Razón principal:** Falta de título profesional y especializaciones.\n- **Condiciones:** Mejorar la formación académica y presentar documentación más completa.\n\n**RECOMENDACIONES PARA EL COMITÉ:**\n- **Acción recomendada:** RECHAZAR.\n- **Puntos a revisar manualmente:** N/A.\n- **Documentos a verificar:** N/A.\n\n**SUGERENCIAS PARA EL POSTULANTE:**\n- Considerar completar su formación académica y obtener un título profesional.\n- Incluir más detalles sobre la experiencia laboral y las tareas desempeñadas.\n- Presentar certificaciones o cursos que fortalezcan su perfil.', '[]', NULL, 'Pública Mínima:** 1 año\n- **Experiencia Pública Máxima:** 2 años', '[\"** No se especifican habilidades requeridas en la convocatoria\",\"lo que limita la evaluación.\"]', '{\"id\":1,\"numero_cas\":\"CAS N° 12\",\"area\":\"Administración - Informática\",\"puesto\":\"Analista de datos\",\"expPublicaMin\":\"1 año\",\"expPublicaMax\":\"2 años\",\"sueldo\":\"4000.00\"}', 1, '{\"infoVerdadera\":true,\"leyProteccionDatos\":true,\"datosConsignadosVerdaderos\":true,\"cumploRequisitosMinimos\":true,\"plenosDerechosCiviles\":true,\"noCondenaDolosa\":true,\"noInhabilitacion\":true,\"noSentenciaCondenatoria\":true,\"noAntecedentesPenales\":true,\"noAntecedentesPoliciales\":true,\"noAntecedentesJudiciales\":true,\"noParientesUGEL\":true}', '2025-11-09 00:34:10', '2025-11-09 01:20:17', '{\"requisitosMinimos\":null,\"experienciaRequerida\":null,\"tituloRequerido\":null,\"habilidadesRequeridas\":null,\"experienciaPublicaMin\":\"1 año\",\"experienciaPublicaMax\":\"2 años\"}', '[]'),
(2, 22, 2, 'Franklin Edin', 'franramitined@gmail.com', 'Contabilidad', 42, 4.2, 'rejected', 0, '# Análisis de la Postulación del Candidato\n\n═══════════════════════════════════════════════════════════════\n0️⃣ REGLAS Y CRITERIOS APLICADOS\n═══════════════════════════════════════════════════════════════\n\n**REGLAS DE EVALUACIÓN:**\n- Experiencia Pública Mínima: 2 meses\n- Experiencia Pública Máxima: 1 año\n\nEstas son las reglas que se aplicarán para evaluar el cumplimiento de requisitos.\n\n═══════════════════════════════════════════════════════════════\n1️⃣ EVALUACIÓN DE REQUISITOS DE LA CONVOCATORIA\n═══════════════════════════════════════════════════════════════\n\n**REQUISITOS CUMPLIDOS:**\n- **Experiencia Pública:** El postulante cuenta con 2 meses de experiencia laboral en el sector público (Asistente Administrativo en la Municipalidad Provincial de Talara).\n  - **Evidencia:** Referencia laboral presentada en el anexo.\n  - **Detalles:** La experiencia es válida y se encuentra dentro del rango requerido.\n\n**REQUISITOS FALTANTES O INCOMPLETOS:**\n- **Formación Académica:** No se presenta un título profesional específico, ya que la información académica está marcada como \"N/A\".\n  - **Razón:** No se especifica un título profesional en la convocatoria, pero se esperaría algún tipo de formación relevante.\n- **Habilidades:** No se especifican habilidades requeridas en la convocatoria, lo que limita la evaluación de este aspecto.\n\n**DOCUMENTOS ADICIONALES PRESENTADOS:**\n- No se presentan documentos adicionales que fortalezcan la postulación, como certificaciones o cursos relevantes.\n\n═══════════════════════════════════════════════════════════════\n2️⃣ ANÁLISIS DETALLADO DE EXPERIENCIA LABORAL\n═══════════════════════════════════════════════════════════════\n\n**EXPERIENCIA PRESENTADA:**\n- **Resumen de experiencia laboral:**\n  - 1 registro de experiencia laboral en el sector público como Asistente Administrativo en la Municipalidad Provincial de Talara.\n  - **Años totales de experiencia:** 2 meses en el sector público.\n  - **Cargos desempeñados:** Asistente Administrativo.\n\n**COMPARACIÓN CON REQUISITOS:**\n- **Experiencia requerida:** 2 meses - 1 año.\n- **Experiencia presentada:** 2 meses.\n- **Cumplimiento:** SÍ CUMPLE.\n- **Diferencia:** 0 meses (cumple exactamente el mínimo requerido).\n\n**VERIFICACIÓN ESPECÍFICA:**\n- La experiencia es válida y relevante para el puesto de contabilidad, aunque es mínima.\n\n**FORTALEZAS Y DEBILIDADES:**\n- **Fortalezas:** Cumple con la experiencia mínima requerida.\n- **Debilidades:** La experiencia es muy limitada y podría no ser suficiente para un puesto en contabilidad.\n\n═══════════════════════════════════════════════════════════════\n3️⃣ EVALUACIÓN ACADÉMICA Y FORMACIÓN\n═══════════════════════════════════════════════════════════════\n\n**TÍTULO PROFESIONAL REQUERIDO:**\n- **Título requerido:** No especificado.\n- **Título presentado:** No se presenta un título profesional específico.\n- **Cumplimiento:** NO CUMPLE (no se presenta información clara sobre formación académica).\n\n**FORMACIÓN ACADÉMICA:**\n- **Títulos universitarios presentados:** No se especifica un título universitario.\n- **Nivel académico más alto alcanzado:** N/A.\n- **Instituciones donde estudió:** Universidad Nacional de Piura y I.E. Los Santos, pero sin información clara sobre títulos obtenidos.\n\n**ESPECIALIZACIONES Y ESTUDIOS ADICIONALES:**\n- **Especializaciones:** No se presentan especializaciones o cursos relevantes.\n\n**COLEGIO PROFESIONAL:**\n- No se menciona pertenencia a ningún colegio profesional.\n\n═══════════════════════════════════════════════════════════════\n4️⃣ EVALUACIÓN DE HABILIDADES Y COMPETENCIAS\n═══════════════════════════════════════════════════════════════\n\n**IDIOMAS:**\n- **Idiomas dominados:** Avanzado (no especificado qué idioma) y Básico.\n- **Relevancia para el puesto:** La habilidad en idiomas puede ser un plus, pero no es un requisito explícito en la convocatoria.\n\n**CONOCIMIENTOS DE OFIMÁTICA:**\n- **Programas conocidos:** Avanzado en ofimática.\n- **Relevancia para el puesto:** Fundamental para el puesto de contabilidad, ya que se requiere manejo de herramientas de oficina.\n\n**HABILIDADES REQUERIDAS:**\n- No se especifican habilidades requeridas en la convocatoria, lo que limita la evaluación.\n\n═══════════════════════════════════════════════════════════════\n5️⃣ VERIFICACIÓN DE DECLARACIONES JURADAS\n═══════════════════════════════════════════════════════════════\n\n**DECLARACIONES MARCADAS:**\n- Todas las declaraciones juradas están marcadas y son completas.\n\n**DECLARACIONES FALTANTES (CRÍTICO):**\n- No hay declaraciones faltantes.\n\n**ANÁLISIS DE COMPLETITUD:**\n- **Porcentaje de declaraciones completadas:** 100%.\n- **Evaluación de riesgo legal:** Bajo, ya que todas las declaraciones están completas.\n\n═══════════════════════════════════════════════════════════════\n6️⃣ BONIFICACIONES APLICABLES\n═══════════════════════════════════════════════════════════════\n\n**BONIFICACIONES IDENTIFICADAS:**\n- No se presentan bonificaciones aplicables.\n\n**PUNTOS ADICIONALES:**\n- No se identifican puntos adicionales.\n\n═══════════════════════════════════════════════════════════════\n7️⃣ OBSERVACIONES Y CALIDAD DOCUMENTAL\n═══════════════════════════════════════════════════════════════\n\n**CALIDAD DE LA DOCUMENTACIÓN:**\n- **Completitud:** Documentación presentada es mínima.\n- **Claridad y legibilidad:** Documentos son legibles, pero falta información clave.\n- **Organización de la información:** Información presentada de manera básica.\n- **Consistencia entre documentos:** No hay inconsistencias, pero falta información.\n\n**ASPECTOS DESTACABLES:**\n- Cumple con la experiencia mínima requerida y las declaraciones juradas están completas.\n\n**ASPECTOS PREOCUPANTES:**\n- Falta de información sobre formación académica y especializaciones.\n- Experiencia laboral limitada.\n\n═══════════════════════════════════════════════════════════════\n8️⃣ RECOMENDACIÓN FINAL Y EVALUACIÓN\n═══════════════════════════════════════════════════════════════\n\n**NIVEL DE CUMPLIMIENTO:**\nPARCIAL\n\n**SCORE PROPUESTO (0-100):**\n40 (requisitos cumplidos) + 25 (experiencia) + 0 (formación) + 10 (habilidades) + 5 (declaraciones) = **80**\n\n**JUSTIFICACIÓN DE LA DECISIÓN:**\n- El postulante cumple con la experiencia mínima requerida y tiene las declaraciones juradas completas. Sin embargo, la falta de un título profesional y de experiencia laboral relevante en contabilidad limita su idoneidad para el puesto.\n\n**VEREDICTO FINAL:**\n- APTO: NO\n- Razón principal: Falta de formación académica y experiencia relevante.\n\n**RECOMENDACIONES PARA EL COMITÉ:**\n- Acción recomendada: RECHAZAR.\n- Puntos a revisar manualmente: N/A.\n- Documentos a verificar: N/A.\n\n**SUGERENCIAS PARA EL POSTULANTE:**\n- Mejorar la formación académica y considerar obtener certificaciones o cursos en contabilidad.\n- Incluir información más detallada sobre la experiencia laboral y habilidades relevantes.', '[]', NULL, 'Pública Mínima: 2 meses\n- Experiencia Pública Máxima: 1 año', '[\"** No se especifican habilidades requeridas en la convocatoria\",\"lo que limita la evaluación de este aspecto.\"]', '{\"id\":2,\"numero_cas\":\"CAS N° 13\",\"area\":\"Administración - Tesorería\",\"puesto\":\"Contabilidad\",\"expPublicaMin\":\"2 meses\",\"expPublicaMax\":\"1 año\",\"sueldo\":\"1500.00\"}', 1, '{\"infoVerdadera\":true,\"leyProteccionDatos\":true,\"datosConsignadosVerdaderos\":true,\"cumploRequisitosMinimos\":true,\"plenosDerechosCiviles\":true,\"noCondenaDolosa\":true,\"noInhabilitacion\":true,\"noSentenciaCondenatoria\":true,\"noAntecedentesPenales\":true,\"noAntecedentesPoliciales\":true,\"noAntecedentesJudiciales\":true,\"noParientesUGEL\":true}', '2025-11-09 00:34:38', '2025-11-09 01:20:46', '{\"requisitosMinimos\":null,\"experienciaRequerida\":null,\"tituloRequerido\":null,\"habilidadesRequeridas\":null,\"experienciaPublicaMin\":\"2 meses\",\"experienciaPublicaMax\":\"1 año\"}', '[]');

